import{_ as t,o as e,c as n,ag as i}from"./chunks/framework.6MCaaFDc.js";const g=JSON.parse('{"title":"SQL","description":"","frontmatter":{"title":"SQL","parent":"Practical (Paper 1)","nav_order":3,"has_children":true},"headers":[],"relativePath":"practical/sql/index.md","filePath":"practical/sql/index.md"}'),r={name:"practical/sql/index.md"};function s(l,a,d,o,c,h){return e(),n("div",null,[...a[0]||(a[0]=[i('<h1 id="sql-—-structured-query-language" tabindex="-1">SQL — Structured Query Language <a class="header-anchor" href="#sql-—-structured-query-language" aria-label="Permalink to &quot;SQL — Structured Query Language&quot;">​</a></h1><p>SQL is the language used to interact with relational databases. In the IT examination, you will be given a pre-populated database and asked to write queries that retrieve, filter, sort, group and manipulate data. In Grade 12, you may also be required to connect a Delphi application to a database.</p><h2 id="what-s-in-this-section" tabindex="-1">What&#39;s in this section <a class="header-anchor" href="#what-s-in-this-section" aria-label="Permalink to &quot;What&#39;s in this section&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>What you&#39;ll learn</th></tr></thead><tbody><tr><td><a href="./select-basics.html">SELECT Basics</a></td><td>SELECT, FROM, WHERE, ORDER BY, DISTINCT — retrieving and filtering data</td></tr><tr><td><a href="./select-advanced.html">SELECT Advanced</a></td><td>Aggregate functions (COUNT, SUM, AVG, MIN, MAX), GROUP BY, HAVING</td></tr><tr><td><a href="./joins.html">Joins</a></td><td>INNER JOIN, LEFT JOIN — combining data from multiple tables</td></tr><tr><td><a href="./data-manipulation.html">Data Manipulation (DML)</a></td><td>INSERT INTO, UPDATE, DELETE — adding and changing records</td></tr><tr><td><a href="./ddl.html">DDL</a></td><td>CREATE TABLE, ALTER TABLE, DROP TABLE — defining database structure</td></tr><tr><td><a href="./delphi-database.html">Delphi &amp; Databases</a></td><td>Connecting Delphi to a database, TADOConnection, TADOQuery, displaying results</td></tr></tbody></table><h2 id="sql-in-the-exam" tabindex="-1">SQL in the exam <a class="header-anchor" href="#sql-in-the-exam" aria-label="Permalink to &quot;SQL in the exam&quot;">​</a></h2><ul><li>SQL is usually worth <strong>15–25% of Paper 1 marks</strong>.</li><li>You are given a <strong>database file</strong> (typically Microsoft Access .mdb or .accdb).</li><li>Questions escalate from simple SELECT to multi-table joins and DML.</li><li>Spelling of SQL keywords and field names must be <strong>exact</strong> — a typo means no marks.</li></ul><h2 id="caps-alignment" tabindex="-1">CAPS alignment <a class="header-anchor" href="#caps-alignment" aria-label="Permalink to &quot;CAPS alignment&quot;">​</a></h2><p>SQL is assessed in <strong>Paper 1</strong> across Grades 10–12 under the Data &amp; Information Management practical component.</p><ul><li><strong>Grade 10</strong> — Basic SELECT with WHERE and ORDER BY.</li><li><strong>Grade 11</strong> — Aggregate functions, GROUP BY, HAVING, simple joins.</li><li><strong>Grade 12</strong> — Complex joins, DML (INSERT/UPDATE/DELETE), DDL, Delphi database integration.</li></ul>',9)])])}const m=t(r,[["render",s]]);export{g as __pageData,m as default};
